"""Training quality-of-life helpers for iPad PyTorch.

Five utilities — all pure Python, all opt-in (zero overhead when not used):

  - OOMGuard          : auto-halve batch size and retry on out-of-memory
  - MemoryProfiler    : RSS snapshots at named checkpoints
  - KVCache           : per-layer key/value cache for autoregressive inference
  - TrainingMonitor   : loss / throughput / ETA / RAM dashboard for the terminal
  - AutoCheckpointer  : periodic save of model + optimizer state, with resume

Usage:
    from _cb_training import (
        OOMGuard, MemoryProfiler, KVCache, TrainingMonitor, AutoCheckpointer
    )
"""
from __future__ import annotations
import gc
import os
import time
import resource
from typing import Callable, Optional

__all__ = ["OOMGuard", "MemoryProfiler", "KVCache", "TrainingMonitor",
           "AutoCheckpointer", "rss_mb", "is_oom_error"]


# ─── shared helpers ────────────────────────────────────────────────

def rss_mb() -> float:
    """Resident set size in MB. macOS/iOS reports bytes from getrusage."""
    return resource.getrusage(resource.RUSAGE_SELF).ru_maxrss / 1e6


def is_oom_error(e: BaseException) -> bool:
    """Detect the various flavours of 'we ran out of memory' that
    PyTorch / Python / libc throw at you. They're not all MemoryError."""
    if isinstance(e, MemoryError):
        return True
    msg = str(e).lower()
    return any(s in msg for s in (
        "out of memory", "cannot allocate", "alloc failed",
        "bad_alloc", "insufficient memory",
    ))


def _fmt_time(sec: float) -> str:
    if sec < 60:
        return f"{sec:.0f}s"
    if sec < 3600:
        m, s = divmod(int(sec), 60)
        return f"{m}m{s:02d}s"
    h, rem = divmod(int(sec), 3600)
    m = rem // 60
    return f"{h}h{m:02d}m"


# ─── 1. OOMGuard ───────────────────────────────────────────────────

class OOMGuard:
    """Adapt batch size on OOM. Use as a step driver inside a training
    loop:

        guard = OOMGuard(start_batch_size=8)
        for big_batch in dataloader:
            loss = guard.step(
                lambda bs: train_one_step(big_batch[:bs])
            )

    On OOM, `step` runs `gc.collect()`, halves `guard.batch_size`, and
    retries the same big_batch. If the minimum batch size is also OOM
    it propagates. The user can inspect `guard.oom_events` afterwards
    to know if it ever fired.

    Why a callable instead of a context manager: the retry needs to
    rerun your step from the start (autograd graph from the failed
    attempt is half-built), so a `with` block can't do it cleanly."""

    def __init__(self, start_batch_size: int, min_batch_size: int = 1,
                 verbose: bool = True):
        if start_batch_size < min_batch_size:
            raise ValueError("start_batch_size < min_batch_size")
        self.batch_size = start_batch_size
        self.min_batch_size = min_batch_size
        self.verbose = verbose
        self.oom_events = 0

    def step(self, fn: Callable[[int], object], *args, **kwargs):
        """Call `fn(batch_size, *args, **kwargs)`. On OOM, gc + halve +
        retry. Returns whatever fn returns."""
        while True:
            try:
                return fn(self.batch_size, *args, **kwargs)
            except BaseException as e:
                if not is_oom_error(e):
                    raise
                if self.batch_size <= self.min_batch_size:
                    if self.verbose:
                        print(f"[OOMGuard] OOM at min batch size "
                              f"({self.min_batch_size}) — giving up.")
                    raise
                old = self.batch_size
                self.batch_size = max(self.min_batch_size,
                                      self.batch_size // 2)
                self.oom_events += 1
                gc.collect()
                if self.verbose:
                    print(f"[OOMGuard] OOM at batch={old}, "
                          f"retrying at batch={self.batch_size}")


# ─── 2. MemoryProfiler ─────────────────────────────────────────────

class MemoryProfiler:
    """RSS snapshots between named checkpoints. Useful when diagnosing
    where a forward pass blows up.

        prof = MemoryProfiler()
        prof.mark("start")
        model = load_model()
        prof.mark("model_loaded")
        out = model(x)
        prof.mark("after_forward")
        prof.report()
    """

    def __init__(self):
        self.marks: list[tuple[str, float]] = []  # (name, rss_mb)

    def mark(self, name: str):
        self.marks.append((name, rss_mb()))

    def report(self):
        if not self.marks:
            print("[MemoryProfiler] no marks recorded")
            return
        print(f"{'checkpoint':<32}  {'RSS (MB)':>10}  {'Δ prev':>10}  {'Δ start':>10}")
        base = self.marks[0][1]
        prev = base
        for name, rss in self.marks:
            d_prev = rss - prev
            d_start = rss - base
            print(f"{name:<32}  {rss:>10.1f}  {d_prev:>+10.1f}  {d_start:>+10.1f}")
            prev = rss

    def reset(self):
        self.marks.clear()


# ─── 3. KVCache ────────────────────────────────────────────────────

class KVCache:
    """Per-layer Key/Value cache for autoregressive transformer inference.

    Standard transformer attention recomputes K, V over the full prefix
    every time you generate a new token, which is O(seq²). KV caching
    is the standard fix: store K and V across calls and only compute
    the new token's K, V each step.

        cache = KVCache(n_layers=24)
        # ... generation loop ...
        for layer_idx, attn_layer in enumerate(model.layers):
            k_new = attn_layer.key_proj(hidden_state)   # (B, H, 1, D)
            v_new = attn_layer.value_proj(hidden_state)
            k_full, v_full = cache.update(layer_idx, k_new, v_new)
            # use k_full, v_full as keys/values for attention

    `update` returns the concatenated K, V. The caller does the actual
    attention math (which our matmul / SDPA patches will already GPU-
    accelerate).

    Limits: this implementation re-allocates via torch.cat each call,
    which is O(seq) per step. A proper implementation pre-allocates a
    [batch, heads, max_seq, head_dim] buffer and writes into a slice.
    The torch.cat version is correct and simple; switch later if it
    becomes a bottleneck."""

    def __init__(self, n_layers: int, max_seq: Optional[int] = None):
        self.n_layers = n_layers
        self.max_seq = max_seq
        # Each slot is None (uninitialised) or (K, V) tensors.
        self._cache: list[Optional[tuple]] = [None] * n_layers

    def update(self, layer_idx: int, k_new, v_new):
        """Append k_new, v_new to layer's cache. Returns (K_full, V_full).
        Last dim of -2 is treated as the sequence axis (standard HF
        attention layout: B, H, S, D)."""
        import torch
        prev = self._cache[layer_idx]
        if prev is None:
            k_full, v_full = k_new, v_new
        else:
            k_prev, v_prev = prev
            k_full = torch.cat([k_prev, k_new], dim=-2)
            v_full = torch.cat([v_prev, v_new], dim=-2)
        if self.max_seq is not None and k_full.shape[-2] > self.max_seq:
            # Sliding window — keep only the most recent max_seq tokens.
            k_full = k_full[..., -self.max_seq:, :].contiguous()
            v_full = v_full[..., -self.max_seq:, :].contiguous()
        self._cache[layer_idx] = (k_full, v_full)
        return k_full, v_full

    def reset(self):
        """Drop all cached state. Call between independent generations."""
        for i in range(self.n_layers):
            self._cache[i] = None

    def length(self, layer_idx: int = 0) -> int:
        c = self._cache[layer_idx]
        return 0 if c is None else c[0].shape[-2]

    def memory_mb(self) -> float:
        """Estimated RAM held by the cache, summed across all layers."""
        total = 0
        for c in self._cache:
            if c is None:
                continue
            k, v = c
            total += k.numel() * k.element_size()
            total += v.numel() * v.element_size()
        return total / 1e6


# ─── 4. TrainingMonitor ────────────────────────────────────────────

class TrainingMonitor:
    """Terminal-based training progress display. Tracks loss (raw and
    EMA-smoothed), throughput, ETA, and process RSS. Cheap — every
    `update` is a few divisions and assignments. Only `print` does I/O.

        mon = TrainingMonitor(total_steps=1000, log_every=10)
        for step, batch in enumerate(dataloader):
            loss = train_step(batch)
            mon.update(step, loss=loss.item())
            mon.maybe_print(step)

    `maybe_print` prints only every `log_every` steps so the terminal
    doesn't get flooded. `mon.print()` is unconditional if you want it."""

    def __init__(self, total_steps: int, log_every: int = 10,
                 ema_alpha: float = 0.1, show_bridge_stats: bool = True):
        self.total_steps = total_steps
        self.log_every = log_every
        self.ema_alpha = ema_alpha
        self.show_bridge_stats = show_bridge_stats
        self._start = None
        self._last = None
        self.step = 0
        self.loss = None
        self.loss_ema = None
        self.steps_per_sec = 0.0
        # Snapshot the bridge stats at start so we can show GPU dispatches
        # incurred during THIS run rather than session-cumulative.
        self._bridge_start_stats = self._fetch_bridge_stats()

    @staticmethod
    def _fetch_bridge_stats():
        try:
            import _torch_metal_bridge as b
            return b.stats()
        except Exception:
            return None

    def update(self, step: int, loss: Optional[float] = None):
        now = time.perf_counter()
        if self._start is None:
            self._start = now
            self._last = now
        else:
            dt = now - self._last
            inst = 1.0 / dt if dt > 0 else 0.0
            if self.steps_per_sec == 0:
                self.steps_per_sec = inst
            else:
                a = self.ema_alpha
                self.steps_per_sec = (1 - a) * self.steps_per_sec + a * inst
            self._last = now
        self.step = step
        if loss is not None:
            self.loss = loss
            if self.loss_ema is None:
                self.loss_ema = loss
            else:
                a = self.ema_alpha
                self.loss_ema = (1 - a) * self.loss_ema + a * loss

    def maybe_print(self, step: int):
        if step % self.log_every == 0:
            self.print()

    def print(self):
        elapsed = (time.perf_counter() - self._start) if self._start else 0
        remaining = max(0, self.total_steps - self.step)
        eta = remaining / max(self.steps_per_sec, 1e-9)
        loss_s = f"loss={self.loss:.4f}" if self.loss is not None else "loss=--"
        ema_s = f"(ema={self.loss_ema:.4f})" if self.loss_ema is not None else ""
        gpu_s = ""
        if self.show_bridge_stats and self._bridge_start_stats is not None:
            now_stats = self._fetch_bridge_stats() or {}
            delta_dispatches = sum(
                now_stats.get(k, 0) - self._bridge_start_stats.get(k, 0)
                for k in ("dtype_fp32", "dtype_fp16", "dtype_bf16_cast")
            )
            gpu_s = f"  gpu={delta_dispatches}"
        print(f"step {self.step:5d}/{self.total_steps}  "
              f"{loss_s} {ema_s}  "
              f"{self.steps_per_sec:5.2f}it/s  "
              f"el={_fmt_time(elapsed)} eta={_fmt_time(eta)}  "
              f"ram={rss_mb():.0f}M{gpu_s}")


# ─── 5. AutoCheckpointer ───────────────────────────────────────────

class AutoCheckpointer:
    """Periodic save of model + optimizer state during training.

    Survives crashes, force-quits, and iOS suspension. The most recent
    checkpoint is symlinked as `latest.pt` for easy resume. Old
    checkpoints beyond `keep_last_n` are pruned to control disk use.

    Toggle: enabled by default. Override per-instance with the
    `enabled=` constructor arg, or globally via the environment variable
    `CODEBENCH_AUTO_CHECKPOINT` (set to `0` / `false` / `off` to disable).

    Example:
        ckpt = AutoCheckpointer(model, optimizer,
                                output_dir="~/Documents/runs/my_run",
                                every_n_steps=50)

        start = ckpt.maybe_resume()   # 0 if no prior run, else last_step + 1

        for step in range(start, total_steps):
            loss = train_step(batch)
            ckpt.maybe_save(step, loss=loss.item())

        ckpt.save_final()
    """

    def __init__(self, model, optimizer, output_dir: str,
                 every_n_steps: int = 100,
                 keep_last_n: int = 3,
                 enabled: Optional[bool] = None,
                 verbose: bool = True):
        self.model = model
        self.optimizer = optimizer
        self.output_dir = os.path.expanduser(output_dir)
        self.every_n_steps = max(1, int(every_n_steps))
        self.keep_last_n = max(1, int(keep_last_n))
        self.verbose = verbose

        # Resolution order: explicit constructor arg > env var > default True
        if enabled is None:
            env = os.environ.get("CODEBENCH_AUTO_CHECKPOINT", "1").lower()
            enabled = env not in ("0", "false", "no", "off", "")
        self.enabled = enabled

        self.last_step_saved = -1
        self.saves_count = 0

        if self.enabled:
            os.makedirs(self.output_dir, exist_ok=True)

    # ─── public API ───────────────────────────────────────────────

    def maybe_resume(self) -> int:
        """If a previous checkpoint exists, load it and return the next
        step number to run. Returns 0 if none exists or disabled."""
        if not self.enabled:
            return 0
        latest = self._find_latest()
        if latest is None:
            return 0
        return self.load(latest)

    def maybe_save(self, step: int, **extra):
        """Save if `step` is at least `every_n_steps` past the last save.
        No-op if disabled. Returns the saved path or None."""
        if not self.enabled:
            return None
        if step - self.last_step_saved < self.every_n_steps:
            return None
        return self.save(step, **extra)

    def save(self, step: int, **extra) -> Optional[str]:
        """Force a save now. Stores `extra` kwargs alongside model state
        so the training loop can stash loss / LR / etc. for inspection."""
        if not self.enabled:
            return None
        import torch
        path = os.path.join(self.output_dir, f"ckpt-step-{step:06d}.pt")
        torch.save({
            "step": step,
            "model_state_dict": self.model.state_dict(),
            "optimizer_state_dict": self.optimizer.state_dict(),
            "extra": dict(extra),
        }, path)
        self._update_latest(path)
        self._prune()
        self.last_step_saved = step
        self.saves_count += 1
        if self.verbose:
            print(f"[AutoCheckpointer] saved step={step} → "
                  f"{os.path.basename(path)}")
        return path

    def save_final(self, **extra) -> Optional[str]:
        """Force a save under `final.pt`. Excluded from pruning."""
        if not self.enabled:
            return None
        import torch
        path = os.path.join(self.output_dir, "final.pt")
        torch.save({
            "step": self.last_step_saved,
            "model_state_dict": self.model.state_dict(),
            "optimizer_state_dict": self.optimizer.state_dict(),
            "extra": dict(extra),
        }, path)
        if self.verbose:
            print(f"[AutoCheckpointer] saved final → {path}")
        return path

    def load(self, path: str) -> int:
        """Load model + optimizer state from `path`. Returns the step
        number to resume FROM (i.e. last saved step + 1)."""
        import torch
        ckpt = torch.load(path, map_location="cpu")
        self.model.load_state_dict(ckpt["model_state_dict"])
        self.optimizer.load_state_dict(ckpt["optimizer_state_dict"])
        self.last_step_saved = int(ckpt.get("step", -1))
        if self.verbose:
            print(f"[AutoCheckpointer] resumed from {path} "
                  f"(step={self.last_step_saved})")
        return self.last_step_saved + 1

    # ─── internals ────────────────────────────────────────────────

    def _update_latest(self, path: str):
        """Point `latest.pt` at the just-saved checkpoint."""
        latest = os.path.join(self.output_dir, "latest.pt")
        base = os.path.basename(path)
        try:
            if os.path.lexists(latest):
                os.unlink(latest)
            os.symlink(base, latest)
        except (OSError, NotImplementedError):
            # Filesystem doesn't support symlinks (sandboxed iCloud?) —
            # fall back to a sidecar pointer file.
            with open(latest + ".name", "w") as f:
                f.write(base)

    def _find_latest(self) -> Optional[str]:
        latest = os.path.join(self.output_dir, "latest.pt")
        if os.path.islink(latest):
            target = os.path.join(self.output_dir, os.readlink(latest))
            if os.path.exists(target):
                return target
        # Sidecar fallback
        sidecar = latest + ".name"
        if os.path.exists(sidecar):
            try:
                with open(sidecar) as f:
                    name = f.read().strip()
                target = os.path.join(self.output_dir, name)
                if os.path.exists(target):
                    return target
            except OSError:
                pass
        # Last-ditch: scan for highest-numbered ckpt-step-NNNNNN.pt
        try:
            entries = sorted(
                f for f in os.listdir(self.output_dir)
                if f.startswith("ckpt-step-") and f.endswith(".pt")
            )
        except OSError:
            return None
        if not entries:
            return None
        return os.path.join(self.output_dir, entries[-1])

    def _prune(self):
        """Delete checkpoints older than the `keep_last_n` most recent."""
        try:
            entries = sorted(
                f for f in os.listdir(self.output_dir)
                if f.startswith("ckpt-step-") and f.endswith(".pt")
            )
        except OSError:
            return
        excess = len(entries) - self.keep_last_n
        for old in entries[:max(0, excess)]:
            try:
                os.unlink(os.path.join(self.output_dir, old))
            except OSError:
                pass
